import { useState } from "react";
import { useNavigate } from "react-router-dom";
import PhoneFrame from "../components/PhoneFrame";
import ProgressBar from "../components/ProgressBar";

const tiers = [
  { label: "Budget", budget: "₹350–500", meals: "Dhabas, local eateries", total: "~₹2,000 total", bar: "28%", perDay: "₹350/day" },
  { label: "Comfort", budget: "₹600–800", meals: "Cafés, mid-range restaurants", total: "~₹3,500 total", bar: "55%", perDay: "₹700/day" },
  { label: "Premium", budget: "₹1,000–1,500", meals: "Restaurants, fine dining", total: "~₹6,000 total", bar: "90%", perDay: "₹1,200/day" },
];

const Food = () => {
  const [active, setActive] = useState(0);
  const navigate = useNavigate();
  const t = tiers[active];
  return (
    <PhoneFrame time="9:47">
      <div className="app-header">
        <span className="back-link" onClick={() => navigate("/stay")}>← Back</span>
        <span className="logo-text">travel<span className="logo-dot">blurry</span></span>
        <span className="header-action" onClick={() => navigate("/plan")}>Skip all</span>
      </div>

      <div className="content-scroll">
        <ProgressBar doneCount={3} />
        <div className="screen-title">Food preference</div>
        <div className="screen-sub" style={{ marginBottom: 18 }}>Sets your daily food budget. You choose where to eat.</div>

        <div className="seg-control">
          {tiers.map((tier, i) => (
            <div key={tier.label} className={`seg-opt${active === i ? " active" : ""}`} onClick={() => setActive(i)}>{tier.label}</div>
          ))}
        </div>

        <div className="seg-detail">
          <div className="seg-detail-row"><span className="seg-detail-label">Daily food budget</span><span className="seg-detail-val">{t.budget}</span></div>
          <div className="seg-detail-row"><span className="seg-detail-label">Typical meals</span><span className="seg-detail-val">{t.meals}</span></div>
          <div className="seg-detail-row"><span className="seg-detail-label">For 5 days</span><span className="seg-detail-val" style={{ color: "#185FA5" }}>{t.total}</span></div>
        </div>

        <div style={{ height: 4, background: "#F0F2F5", borderRadius: 4, marginBottom: 14 }}>
          <div style={{ width: t.bar, height: "100%", background: "#185FA5", borderRadius: 4 }}></div>
        </div>

        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 20 }}>
          {tiers.map((tier, i) => (
            <div key={tier.label} style={{ textAlign: "center", flex: 1 }}>
              <div style={{ fontSize: 12, fontWeight: active === i ? 500 : 400, color: active === i ? "#185FA5" : "#6B7280" }}>{tier.label}</div>
              <div style={{ fontSize: 10, color: "#9CA3AF" }}>{tier.perDay}</div>
            </div>
          ))}
        </div>

        <div style={{ background: "#FFF8E6", border: "0.5px solid #FAC775", borderRadius: 10, padding: "10px 12px" }}>
          <div style={{ fontSize: 11, color: "#633806" }}>Budget mode recommended — keeps ₹10,800 for transport, stay, and local travel.</div>
        </div>
      </div>

      <div className="sticky-bottom">
        <button className="cta-btn" onClick={() => navigate("/local")}>Confirm food preference →</button>
        <div className="skip-link" onClick={() => navigate("/local")}>Skip this step</div>
      </div>
    </PhoneFrame>
  );
};

export default Food;
